int calculateMaxProfit(vector<int>& dailyStockPrices) {
        int maxProfit = 0;
        // Start from day 1 (second day) and look back
        for (size_t i = 1; i < dailyStockPrices.size(); i++) {
            // If today's price is higher than yesterday's, we capture the profit
            if (dailyStockPrices[i] > dailyStockPrices[i - 1]) {
                maxProfit += (dailyStockPrices[i] - dailyStockPrices[i - 1]);
            }
        }
        return maxProfit;
    }

