def calculateMaxProfit(dailyStockPrices: list[int]) -> int:
    max_profit = 0
    # Iterate from index 1 to end
    for i in range(1, len(dailyStockPrices)):
        if dailyStockPrices[i] > dailyStockPrices[i - 1]:
            max_profit += dailyStockPrices[i] - dailyStockPrices[i - 1]
    return max_profit

